text:
&-not-a-wrapper {
  .@{badge-prefix-cls}-zoom-appear,
  .@{badge-prefix-cls}-zoom-enter {
    animation: antNoWrapperZoomBadgeIn @animation-duration-slow @ease-out-back;
  }

  .@{badge-prefix-cls}-zoom-leave {
    animation: antNoWrapperZoomBadgeOut @animation-duration-slow @ease-in-back;
  }

  &:not(.@{badge-prefix-cls}-status) {
    vertical-align: middle;
  }

  .@{number-prefix-cls}-custom-component,
  .@{badge-prefix-cls}-count {
    transform: none;
  }

  .@{number-prefix-cls}-custom-component,
  .@{number-prefix-cls} {
    position: relative;
    top: auto;
    display: block;
    transform-origin: 50% 50%;
  }
}

> li {
  list-style: none;
  box-sizing: border-box;
  margin: 0;
  padding: 0 16px;
  display: inline-block;
  height: 48px;
  line-height: 48px;
  border-bottom: 4px solid transparent;
  cursor: pointer;
  user-select: none;
  font-size: 19px;
  color: #ccc;

  &:hover {
    color: white;
    transition: border-color 0.1s linear;
    border-bottom: 4px solid rgba(255, 255, 255, 0.3);
  }

  &.current, &.current:hover {
    border-bottom: 4px solid white;
    color: white;
    cursor: auto;
    font-weight: 300;
  }

  &:active {
    opacity: 0.6;
  }
}

&.type__alert,
      &.type__confirm {
        .@{modal-prefix-cls}__box {
          top: 100px;
          left: 50% !important;
          transform: translateX(-55%);
          margin: @box-margin;
          width: @box-width;

          .@{modal-prefix-cls}__header {
            padding: @header-padding;

            .@{modal-prefix-cls}__title {
              font-size: var(--tv-Modal-responsive-font-size-xl);
            }
          }

          .@{modal-prefix-cls}__body {
            padding: @body-padding;

            .@{modal-prefix-cls}__content {
              .@{modal-prefix-cls}__text {
                font-size: var(--tv-Modal-responsive-font-size-sm);
              }
            }
          }

          .@{modal-prefix-cls}__footer {
            padding: @modal-responsive-space-part @modal-responsive-space @modal-responsive-space;
          }
        }
      }

&.is-plain {
  color: @normal-color;
  fill: @normal-color;
  border-color: @normal-color;
  background-color: @plain-bgcolor;

  &:hover {
    color: @hover-color;
    fill: @hover-color;
    border-color: @hover-color;
  }

  &:focus,
  &:active,
  &.is-active {
    color: @active-color;
    fill: @active-color;
    border-color: @active-color;
    @apply outline-0;
  }

  &.is-disabled,
  &.is-disabled:active,
  &.is-disabled:focus,
  &.is-disabled:hover {
    color: @disabled-bgcolor;
    fill: @disabled-bgcolor;
    border-color: @disabled-bgcolor;
    background-color: @plain-dis-bgcolor;
  }
}

&.filter-option__radios {
  @apply mb-3;
  @apply flex;
  @apply justify-around;

  label.@{grid-radio-prefix-cls} {
    @apply flex;
    @apply items-center;
    @apply w-auto;

    .@{grid-radio-prefix-cls}__label {
      @apply text-color-text-primary;
      @apply text-ellipsis;
      @apply overflow-hidden;
      @apply whitespace-nowrap;
      @apply w-auto;
      max-width: 80%;
    }

    & + .@{grid-radio-prefix-cls} {
      @apply ml-0;
    }

    &:nth-child(2) {
      @apply text-center;
    }

    &:nth-child(3) {
      @apply text-right;
    }
  }
}

& when (not (@bordered-item-cls = null)) {
  // border collapse
  &-item:not(&-last-item) {
    margin-right: -@border-width-base;

    &.@{prefix-cls}-compact-item-rtl {
      margin-right: 0;
      margin-left: -@border-width-base;
    }
  }

  &-item {
    &:hover,
    &:focus,
    &:active {
      > * {
        z-index: 2;
      }
    }

    // Select has an special focus-item
    & when (not (@special-item-cls = null)) {
      &.@{special-item-cls} > * {
        z-index: 2;
      }
    }

    &[disabled] > * {
      z-index: 0;
    }
  }
}

&-primary {
  .btn-primary();

  .@{btn-prefix-cls}-group &:not(:first-child):not(:last-child) {
    border-right-color: @btn-group-border;
    border-left-color: @btn-group-border;

    &:disabled {
      border-color: @btn-default-border;
    }
  }

  .@{btn-prefix-cls}-group &:first-child {
    &:not(:last-child) {
      border-right-color: @btn-group-border;

      &[disabled] {
        border-right-color: @btn-default-border;
      }
    }
  }

  .@{btn-prefix-cls}-group &:last-child:not(:first-child),
  .@{btn-prefix-cls}-group & + & {
    border-left-color: @btn-group-border;

    &[disabled] {
      border-left-color: @btn-default-border;
    }
  }
}

&-small {
  min-width: @switch-sm-min-width;
  height: @switch-sm-height;
  line-height: @switch-sm-height;

  .@{switch-prefix-cls}-inner {
    margin: 0 @switch-sm-inner-margin-min 0 @switch-sm-inner-margin-max;
    font-size: @font-size-sm;
  }

  .@{switch-prefix-cls}-handle {
    width: @switch-sm-pin-size;
    height: @switch-sm-pin-size;
  }

  .@{switch-prefix-cls}-loading-icon {
    top: ((@switch-sm-pin-size - 9px) / 2);
    font-size: 9px;
  }

  &.@{switch-prefix-cls}-checked {
    .@{switch-prefix-cls}-inner {
      margin: 0 @switch-sm-inner-margin-max 0 @switch-sm-inner-margin-min;
    }

    .@{switch-prefix-cls}-handle {
      left: calc(100% - @switch-sm-pin-size - @switch-padding);
    }
  }
}

&__color-select {
  min-width: 220px;
  flex-grow: 1;
  height: 142px;
  position: relative;

  .white {
    background: linear-gradient(to right, #fff, rgba(255, 255, 255, 0));
  }

  .black {
    background: linear-gradient(to top, #000, rgba(0, 0, 0, 0));
  }

  .white,
  .black {
    position: absolute;
    inset: 0;
  }

  .cursor {
    position: absolute;
    width: 12px;
    height: 12px;
    border-radius: 100%;
    border: 1px solid white;
    background: rgba(0, 0, 0, 0.15);
    box-shadow:
      inset 0 0 1px 1px #0000004d,
      0 0 1px 2px #0006;
  }
}

&:not(.@{class-prefix-passcode-input}-seperated) {
  border-radius: var(--border-radius);
  overflow: hidden;
  border: 1px solid var(--border-color);
  .@{class-prefix-passcode-input}-cell:not(:last-child) {
    border-right: 1px solid var(--border-color);
  }
  &.@{class-prefix-passcode-input}-focused {
    border-color: var(--adm-color-primary);
    box-shadow: 0 0 2px 0 var(--adm-color-primary);
    outline: none;
  }
  &.@{class-prefix-passcode-input}-error {
    border-color: var(--adm-color-danger);
    box-shadow: 0 0 2px 0 var(--adm-color-danger);
    animation: 100ms ease-in-out 0s 3 normal none running adm-shake-horizontal;
  }
}

&-meta{
    display: flex;
    flex: 1;
    align-items: flex-start;
    font-size: 0;

    &-avatar {
        margin-right: @list-item-meta-avatar-margin-right;
    }
    &-content {
        flex: 1 0;
    }
    &-title {
        font-weight: bold;
        margin-bottom: 4px;
        color: @text-color;
        font-size: @font-size-base;
        line-height: 22px;
        > a {
            color: @text-color;
            transition: all @transition-time;
            &:hover {
                color: @primary-color;
            }
        }
    }
    &-description {
        color: @text-color-secondary;
        font-size: @font-size-base;
        line-height: 22px;
    }
}

&-scroll {
  position: sticky;
  bottom: 0;
  z-index: @table-sticky-zindex;
  display: flex;
  align-items: center;
  background: lighten(@table-border-color, 80%);
  border-top: 1px solid @table-border-color;
  opacity: 0.6;

  &:hover {
    transform-origin: center bottom;
  }

  &-bar {
    height: 8px;
    background-color: @table-sticky-scroll-bar-bg;
    border-radius: @table-sticky-scroll-bar-radius;

    &:hover {
      background-color: @table-sticky-scroll-bar-active-bg;
    }

    &-active {
      background-color: @table-sticky-scroll-bar-active-bg;
    }
  }
}

&-button {
  position: fixed;
  top: var(--initial-position-top);
  bottom: var(--initial-position-bottom);
  left: var(--initial-position-left);
  right: var(--initial-position-right);
  box-sizing: border-box;
  width: var(--size);
  height: var(--size);
  display: flex;
  justify-content: center;
  align-items: center;
  overflow: hidden;
  cursor: pointer;
  transition: opacity ease 0.15s;
  user-select: none;
  touch-action: none;
  background: var(--background);
  color: var(--adm-color-white);
  border-radius: var(--border-radius);
  z-index: var(--z-index);
}

& pre {
  margin: 1em 0;
  border-radius: 6px;
  border: 1px solid @line-color;
  background-color: #fff;
  padding: 0;
  & code {
    background: transparent;
    margin: 0;
    border: none;
    display: block;
    line-height: 1.5;
    font-size: 13px;
    white-space: pre;
  }
  &::-webkit-scrollbar {
    width: 2px;
    height: 2px;
  }
  &::-webkit-scrollbar-thumb {
    background: @scrollbar-color;
    border-radius: 2px;
  }
  &::-webkit-scrollbar-corner,
  &::-webkit-scrollbar-track-piece,
  &::-webkit-scrollbar-button,
  &::-webkit-scrollbar-track {
    display: none;
  }
}

& ul {
  & li {
    width: 25%;
    margin: 0 ~"calc(25% / 6)";
    height: 65px;
    position: relative;
    display: inline-block;
    background: fade(@primary-color, 55);
    border-radius: 6px;
    &:before {
      content: '';
      display: block;
      width: 24px;
      height: 24px;
      border-radius: 6px;
      background: #fff;
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      margin: auto;
    }
    &:nth-child(2):before {
      transform: rotate(45deg);
    }
    &:nth-child(3):before {
      transform: rotate(45deg);
      filter: blur(2px);
    }
  }
}

& when not (@critical) {
    :where([id]) {
        scroll-margin-top: var(--base-scroll-margin-top);
    }
    .action.skip {
        .page-header & {
            position: absolute;
            .left(@2);
            top: @2;
            z-index: 40;
            text-align: center;
            background: var(--base-bg);
            color: var(--base-color);
            &:hover {
                text-decoration: underline;
            }
            &:focus-within {
                outline-offset: 0;
                padding: @container__padding;
            }
        }

        @media @media-md-down {
            // No need to have "skip" on mobile because layered nav is hidden
            .sidebar & {
                display: none !important;
            }
        }
    }
}

& when (@variationToastCentered) {
    .ui.ui.toast-container .toast-box .centered.toast,
    .ui.ui.toast-container .toast-box .center.aligned.toast {
        text-align: center;
        display: flex;
        justify-content: center;

        & > .content,
        & > .ui.image,
        & > i.icon@{notClose} {
            align-self: center;
        }
    }

    .ui.toast-container .toast-box .toast .centered.content,
    .ui.toast-container .toast-box .toast .center.aligned.content {
        text-align: center;
    }

    .ui.toast-container .toast-box .centered.actions,
    .ui.toast-container .toast-box .center.aligned.actions {
        text-align: center;

        &@{notAttached} > .button@{notFluid} {
            margin-left: @toastActionCenteredMargin;
            margin-right: @toastActionCenteredMargin;
        }
    }
}

&-zero-width {
    & > * {
        overflow: hidden;
    }

    &-trigger {
        position: absolute;
        top: @layout-header-height;
        right: -@layout-zero-trigger-width;
        text-align: center;
        width: @layout-zero-trigger-width;
        height: @layout-zero-trigger-height;
        line-height: @layout-zero-trigger-height;
        background: @layout-sider-background;
        color: #fff;
        font-size: @layout-zero-trigger-width / 2;
        border-radius: 0 @border-radius-base @border-radius-base 0;
        cursor: pointer;
        transition: background .3s ease;

        &:hover {
          background: tint(@layout-sider-background, 10%);
        }

        &&-left {
            right: 0;
            left: -@layout-zero-trigger-width;
            border-radius: @border-radius-base 0 0 @border-radius-base;
        }
    }
}

li {
    margin-bottom: .4em;
    margin-right: .4em;
    a {
        display: inline;
        text-decoration: none;
        border: 1px dashed @color-border;
        border: 1px dashed var(--color-border);
        border-radius: 3px;
        padding: .1em .3em;
        outline: none;

        transition: none;

        span {
            font-size: 0.8em;
            border-left: 1px solid @color-border;
            border-left: 1px solid var(--color-border);
            margin-left: .3em;
            padding: 0 .3em;
        }

        &:hover {
            background: @color-main-text-light;
            background: var(--color-main-text-light);
            color: @color-border-even-lighter;
            color: var(--color-border-even-lighter);
        }
    }
}

&-item {
  min-width: 120px;
  margin: 0;
  padding: @dropdown-vertical-padding @control-padding-horizontal;
  overflow: hidden;
  color: @text-color;
  font-weight: normal;
  font-size: @dropdown-font-size;
  line-height: @dropdown-line-height;
  white-space: nowrap;
  text-overflow: ellipsis;
  cursor: pointer;
  transition: all 0.3s;

  &:hover {
    background: @item-hover-bg;
  }

  &-disabled {
    &,
    &:hover {
      color: @disabled-color;
      background: transparent;
      cursor: not-allowed;

      a {
        color: @disabled-color;
        pointer-events: none;
      }
    }
  }
}

&-confirm {
  &-body {
    .@{dialog-wrap-rtl-cls} & {
      direction: rtl;
    }
    > .@{iconfont-css-prefix} {
      .@{dialog-wrap-rtl-cls} & {
        float: right;
        margin-right: 0;
        margin-left: 16px;
      }
      + .@{confirm-prefix-cls}-title + .@{confirm-prefix-cls}-content {
        .@{dialog-wrap-rtl-cls} & {
          margin-right: 38px;
          margin-left: 0;
        }
      }
    }
  }

  &-btns {
    .@{dialog-wrap-rtl-cls} & {
      text-align: left;
    }
    .@{ant-prefix}-btn + .@{ant-prefix}-btn {
      .@{dialog-wrap-rtl-cls} & {
        margin-right: 8px;
        margin-left: 0;
      }
    }
  }
}

&-handler-wrap {
  position: absolute;
  top: 0;
  right: 0;
  width: 22px;
  height: 100%;
  background: @input-number-handler-bg;
  border-radius: 0 @control-border-radius @control-border-radius 0;
  opacity: 0;
  transition: opacity 0.24s linear 0.1s;

  // Fix input number inside Menu makes icon too large
  // We arise the selector priority by nest selector here
  // https://github.com/ant-design/ant-design/issues/14367
  .@{input-number-prefix-cls}-handler {
    .@{input-number-prefix-cls}-handler-up-inner,
    .@{input-number-prefix-cls}-handler-down-inner {
      display: flex;
      align-items: center;
      justify-content: center;
      min-width: auto;
      margin-right: 0;
      font-size: 7px;
    }
  }

  .@{input-number-prefix-cls}-borderless & {
    border-left-width: 0;
  }
}

input {
  box-sizing: border-box;
  height: 100%;
  margin-right: 8px;
  padding: 0 6px;
  text-align: center;
  background-color: @pagination-item-input-bg;
  border: @border-width-base @border-style-base @border-color-base;
  border-radius: @border-radius-base;
  outline: none;
  transition: border-color 0.3s;

  &:hover {
    border-color: @primary-color;
  }

  &:focus {
    border-color: @primary-color-hover;
    box-shadow: @input-outline-offset @outline-blur-size @outline-width @primary-color-outline;
  }

  &[disabled] {
    color: @disabled-color;
    background: @disabled-bg;
    border-color: @border-color-base;
    cursor: not-allowed;
  }
}

&&-select-picture-card {
  width: @upload-picture-card-size;
  height: @upload-picture-card-size;
  margin-right: 8px;
  margin-bottom: 8px;
  text-align: center;
  vertical-align: top;
  background-color: @background-color-light;
  border: @border-width-base dashed @border-color-base;
  border-radius: @border-radius-base;
  cursor: pointer;
  transition: border-color 0.3s;

  > .@{upload-prefix-cls} {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    text-align: center;
  }

  &:hover {
    border-color: @primary-color;
    .@{upload-prefix-cls}-disabled& {
      border-color: @border-color-base;
    }
  }
}

&__inner {
  @apply relative;
  @apply inline-block;
  @apply whitespace-nowrap;
  @apply align-middle;
  @apply outline-0;
  @apply leading-none;
  @apply font-medium;
  @apply cursor-pointer;
  @apply bg-color-bg-1;
  @apply border border-solid border-color-border;
  @apply border-l-0;
  @apply text-color-text-primary;
  @apply appearance-none;
  @apply text-center;
  @apply box-border;
  @apply m-0;
  @apply transition-all duration-300 ease-linear;
  @apply py-3 px-5;
  @apply text-xs;
  @apply ~'min-w-[theme(spacing.20)]';
  @apply rounded-none;
  .user-select(none);

  &.is-round {
    @apply py-3 px-5;
  }

  &:hover {
    @apply text-color-brand-hover;
  }
}

&.is-only-icon {
  @apply box-border;
  @apply ~"min-w-[auto]";
  max-width: initial;
  line-height: inherit;
  @apply h-4;
  @apply bg-transparent;
  @apply border-0;
  @apply p-0;
  &:hover {
    @apply fill-color-brand-hover;
    @apply text-color-brand-hover;
  }
  &:focus {
    @apply fill-color-brand-focus;
    @apply text-color-brand-focus;
  }
  &:active {
    @apply fill-color-brand-active;
    @apply text-color-brand-active;
  }

  &.is-disabled:hover {
    @apply fill-color-text-disabled;
    @apply text-color-text-disabled;
    @apply bg-transparent;
  }

  &.@{button-prefix-cls}--text  {
    @apply text-xs;
  }
}

> input {
  & + .@{grid-radio-prefix-cls}__icon {
    > svg {
      @apply fill-color-text-disabled;

      path:last-child {
        @apply fill-color-border-disabled;
      }
    }

    &:before {
      @apply border-color-bg-2;
      @apply bg-color-bg-2;
    }

    & + .@{grid-radio-prefix-cls}__label {
      @apply text-color-text-disabled;
    }
  }

  &:checked + .@{grid-radio-prefix-cls}__icon {
    > svg,
    > svg:hover,
    > svg:active {
      @apply fill-color-brand-disabled;

      > path:first-child {
        @apply fill-color-brand-disabled;
      }
    }
  }
}

// 选中状态
    .@{checkbox-prefix-cls}-checked {

        &:hover {
            .@{checkbox-inner-prefix-cls} {
                border-color: @primary-color;
            }
        }

        .@{checkbox-inner-prefix-cls} {
            border-color: @primary-color;
            background-color: @primary-color;

            &:after {
                content: '';
                display: table;
                width: 4px;
                height: 8px;
                position: absolute;
                top: 1px;
                left: 4px;
                border: 2px solid #fff;
                border-top: 0;
                border-left: 0;
                transform: rotate(45deg) scale(1);
                transition: all @transition-time @ease-in-out;
            }
        }
    }

@media only screen and (max-width: @largestMobileScreen) {
  .ui.items:not(.unstackable) > .item {
    flex-direction: column;
    margin: @mobileItemSpacing 0em;
  }
  .ui.items:not(.unstackable) > .item > .image {
    display: block;
    margin-left: auto;
    margin-right: auto;
  }
  .ui.items:not(.unstackable) > .item > .image,
  .ui.items:not(.unstackable) > .item > .image > img {
    max-width: 100% !important;
    width: @mobileImageWidth !important;
    max-height: @mobileImageMaxHeight !important;
  }
  .ui.items:not(.unstackable) > .item > .image + .content {
    display: block;
    padding: @mobileContentImageDistance 0em 0em;
  }
}

> li {
  float: left;
  // Make the list-items overlay the bottom border
  margin-bottom: -1px;

  // Actual tabs (as links)
  > a {
    margin-right: 2px;
    line-height: @line-height-base;
    border: 1px solid transparent;
    border-radius: @border-radius-base @border-radius-base 0 0;
    outline: none;
    &:hover {
      border-color: @nav-tabs-link-hover-border-color @nav-tabs-link-hover-border-color @nav-tabs-border-color;
    }
  }

  // Active state, and its :hover to override normal :hover
  &.@{prefix-cls-nav}-active > a {
    &,
    &:hover,
    &:focus {
      color: @nav-tabs-active-link-hover-color;
      background-color: @nav-tabs-active-link-hover-bg;
      border: 1px solid @nav-tabs-active-link-hover-border-color;
      border-bottom-color: transparent;
      cursor: default;
    }
  }
}

> li {
  position: relative;
  display: block;

  > a {
    position: relative;
    display: block;
    padding: @nav-link-padding;
    color: @nav-link-default-color;
    &:hover,
    &:focus {
      color: @nav-link-hover-color;
      text-decoration: none;
      background-color: @nav-link-hover-bg;
    }
  }

  // Disabled state sets text to gray and nukes hover/tab effects
  &.@{prefix-cls-nav}-disabled > a {
    color: @nav-disabled-link-color;

    &:hover,
    &:focus {
      color: @nav-disabled-link-hover-color;
      text-decoration: none;
      background-color: transparent;
      cursor: @cursor-disabled;
    }
  }
}

> li {
  float: left;
  // Make the list-items overlay the bottom border
  margin-bottom: -1px;

